// Parse Kimi K2.5 Vision response and map to Airtable fields
try {
  const response = $input.first().json;

  if (!response.choices || !response.choices[0]) {
    return [{ json: { error: 'Kimi API returned no choices', details: JSON.stringify(response).substring(0, 500) } }];
  }

  const content = response.choices[0].message.content;
  const cleaned = content.replace(/```json|```/g, '').trim();
  const invoice = JSON.parse(cleaned);

  const filename = $('Prepare Kimi Request').first().json.filename || '';

  // Normalize tax_rate: if < 1, it's decimal (0.21), convert to percentage (21.0)
  let taxPercent = invoice.tax_rate || 0;
  if (taxPercent > 0 && taxPercent < 1) {
    taxPercent = taxPercent * 100;
  }

  // === FINANCIAL SANITY CHECK & AUTO-CORRECT ===
  // Invariant: subtotal + tax_amount = total_amount (within 0.05 tolerance)
  // Common Kimi error: extracts "Ukupno bez PDV" (gross pre-rabat) as subtotal
  // instead of post-rabat taxable base ("Osnovica" in Specifikacija poreza).
  const t = typeof invoice.total_amount === 'number' ? invoice.total_amount : 0;
  const x = typeof invoice.tax_amount === 'number' ? invoice.tax_amount : 0;
  let s = typeof invoice.subtotal === 'number' ? invoice.subtotal : 0;
  const d = typeof invoice.discount_amount === 'number' ? invoice.discount_amount : 0;
  let correctionApplied = null;

  // For credit notes, all values are negative — comparison logic still works because we use abs()
  if (Math.abs((s + x) - t) > 0.05) {
    // Case A: subtotal looks like gross-before-discount; discount accounts for the gap
    if (Math.abs(d) > 0 && Math.abs((s - d + x) - t) <= 0.05) {
      invoice.gross_before_discount = invoice.gross_before_discount ?? s;
      invoice.subtotal = +(s - d).toFixed(2);
      correctionApplied = 'subtracted_discount_from_subtotal';
    } else {
      // Case B: derive subtotal from total - tax (most reliable fallback)
      invoice.gross_before_discount = invoice.gross_before_discount ?? s;
      invoice.subtotal = +(t - x).toFixed(2);
      correctionApplied = 'derived_subtotal_from_total_minus_tax';
    }
    s = invoice.subtotal;
  }

  // Final validation — if still broken, surface as error to WF07
  const finalCheck = Math.abs((s + x) - t);
  const mathOk = finalCheck <= 0.05;


  // Build human-readable items summary for Airtable + Slack
  const items = invoice.line_items || [];
  const itemsSummary = items.map(it => {
    const qty = it.quantity ?? '?';
    const unit = it.unit || '';
    const name = it.item_name || 'unknown';
    return `${name} — ${qty} ${unit}`.trim();
  }).join('\n');
  const itemsCount = items.length;

  // Map to existing Airtable Invoice_Log field names for backward compatibility
  return [{
    json: {
      // === Fields matching current Airtable schema ===
      seller_name: invoice.seller_name || '',
      seller_address: invoice.seller_address || '',
      seller_email: '',
      invoice_number: invoice.invoice_number || '',
      invoice_date: invoice.invoice_date || new Date().toISOString().split('T')[0],
      payment_due_date: invoice.due_date || '',
      po_number: '',
      subtotal: invoice.subtotal,
      total_tax: x,
      total_tax_percent: taxPercent,
      invoice_amount: t,
      currency: invoice.currency || 'EUR',
      // === New fields ===
      document_type: invoice.document_type || 'INVOICE',
      seller_tax_id: invoice.seller_tax_id || '',
      seller_vat_id: invoice.seller_vat_id || '',
      seller_phone: invoice.seller_phone || '',
      seller_bank_account: invoice.seller_bank_account || '',
      buyer_name: invoice.buyer_name || '',
      buyer_address: invoice.buyer_address || '',
      buyer_tax_id: invoice.buyer_tax_id || '',
      gross_before_discount: invoice.gross_before_discount ?? null,
      discount_amount: d,
      payment_method: invoice.payment_method || '',
      previous_balance: invoice.previous_balance || null,
      line_items_json: JSON.stringify(invoice.line_items || []),
      items_summary: itemsSummary,
      items_count: itemsCount,
      notes: invoice.notes || '',
      source_filename: filename,
      ocr_engine: 'kimi-k2.5-vision',
      math_correction: correctionApplied,
      math_check_delta: +finalCheck.toFixed(4),
      // error field must be null for IF node to route correctly
      error: mathOk ? null : `Math validation failed: subtotal(${s}) + tax(${x}) != total(${t}), delta=${finalCheck.toFixed(2)}`
    }
  }];
} catch (err) {
  return [{
    json: {
      error: 'Kimi OCR processing failed: ' + err.message,
      details: JSON.stringify($input.first().json || {}).substring(0, 500)
    }
  }];
}

